/*
 * Electron Main Process (Vibe Tutor)
 *
 * Ingestion Bridge: Android JSON exports -> Hub DB (D:\databases\database.db)
 *
 * Critical constraint: Main process is the sole writer to database.db.
 */



import { app, BrowserWindow, dialog, ipcMain } from 'electron';
import Store from 'electron-store';
import { mkdirSync } from 'node:fs';
import { readFile } from 'node:fs/promises';
import path from 'node:path';
import Database from 'better-sqlite3';

// better-sqlite3 is preferred for Electron (sync + fast transactions).
// NOTE: Requires dependency + rebuild for Electron.

const HUB_DB_PATH = String.raw`D:\databases\database.db`;

const DEV_SERVER_URL = 'http://localhost:5173';
function isDevMode(): boolean {
  return !app.isPackaged || process.env.NODE_ENV === 'development';
}

const ALLOWED_DEV_ORIGINS = new Set(['http://localhost:5173', 'http://127.0.0.1:5173']);

function isAllowedRendererUrl(url: string): boolean {
  try {
    const parsed = new URL(url);
    if (isDevMode()) {
      return ALLOWED_DEV_ORIGINS.has(parsed.origin);
    }

    // In production we load local files.
    return parsed.protocol === 'file:';
  } catch {
    return false;
  }
}

function assertTrustedIpcSender(event: any): void {
  const senderUrl: string | undefined = event?.senderFrame?.url;
  if (!senderUrl || !isAllowedRendererUrl(senderUrl)) {
    throw new Error('Blocked IPC from untrusted sender');
  }
}

type IngestExportArgs =
  | { filePath: string; jsonBlob?: never }
  | { jsonBlob: string; filePath?: never };

interface AndroidExportPayload {
  export_timestamp?: string;
  device_id?: string;
  events?: Array<{
    summary: string;
    tags?: string[];
    timestamp: number;
  }>;
}

interface IngestResult {
  inserted: number;
  skipped: number;
  total: number;
}

function assertString(value: unknown, fieldName: string): string {
  if (typeof value !== 'string' || value.trim().length === 0) {
    throw new Error(`${fieldName} must be a non-empty string`);
  }
  return value;
}

function ensureHubDbDirectoryExists(): void {
  const dir = path.dirname(HUB_DB_PATH);
  // Use sync here; this is startup/handler-level and keeps behavior deterministic.
  mkdirSync(dir, { recursive: true });
}

function openHubDb() {
  ensureHubDbDirectoryExists();

  const db = new Database(HUB_DB_PATH);

  console.info(`[hub-db] opened ${HUB_DB_PATH}`);

  // Pragmas: optimize for single-writer, many-readers, safe-ish performance.
  db.pragma('journal_mode = WAL');
  db.pragma('synchronous = NORMAL');
  db.pragma('busy_timeout = 5000');

  return db;
}

function ensureLearningEventsSchema(db: any): void {
  const row = db
    .prepare("SELECT name FROM sqlite_master WHERE type='table' AND name='learning_events'")
    .get();

  if (row) return;

  // Create minimal schema matching databases/migrations/002_learning_events.sql.
  // IMPORTANT: event_type is constrained; Android chat imports will be stored as event_type='insight'.
  db.exec(`
    CREATE TABLE IF NOT EXISTS learning_events (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      event_type TEXT NOT NULL CHECK(event_type IN ('error', 'success', 'pattern', 'insight')),
      app_source TEXT NOT NULL CHECK(app_source IN ('nova', 'vibe')),
      source_file TEXT,
      source_function TEXT,
      project_id TEXT,
      session_id TEXT,
      timestamp INTEGER NOT NULL,
      title TEXT NOT NULL,
      description TEXT NOT NULL,
      stack_trace TEXT,
      code_snippet TEXT,
      root_cause TEXT,
      solution TEXT,
      prevention_strategy TEXT,
      severity TEXT CHECK(severity IN ('info', 'warning', 'error', 'critical')),
      impact_score REAL DEFAULT 0.0,
      applies_to TEXT,
      confidence REAL DEFAULT 0.5,
      success_rate REAL DEFAULT 0.0,
      times_applied INTEGER DEFAULT 0,
      status TEXT DEFAULT 'active' CHECK(status IN ('active', 'resolved', 'archived')),
      resolved_at INTEGER,
      created_at INTEGER NOT NULL DEFAULT (strftime('%s', 'now')),
      updated_at INTEGER NOT NULL DEFAULT (strftime('%s', 'now'))
    );

    CREATE INDEX IF NOT EXISTS idx_learning_events_type
    ON learning_events(event_type, timestamp DESC);

    CREATE INDEX IF NOT EXISTS idx_learning_events_project
    ON learning_events(project_id);

    CREATE INDEX IF NOT EXISTS idx_learning_events_status
    ON learning_events(status, severity);

    CREATE INDEX IF NOT EXISTS idx_learning_events_session
    ON learning_events(session_id, timestamp);

    CREATE INDEX IF NOT EXISTS idx_learning_events_app_source
    ON learning_events(app_source, event_type, timestamp DESC);

    CREATE TRIGGER IF NOT EXISTS trg_learning_events_updated_at
    AFTER UPDATE ON learning_events
    FOR EACH ROW
    BEGIN
      UPDATE learning_events
      SET updated_at = strftime('%s', 'now')
      WHERE id = NEW.id;
    END;
  `);
}

async function readExportPayload(args: IngestExportArgs): Promise<AndroidExportPayload> {
  if ('filePath' in args) {
    const filePath = assertString(args.filePath, 'filePath');

    if (!filePath.toLowerCase().endsWith('.json')) {
      throw new Error('Only .json export files are supported');
    }

    const raw = await readFile(filePath, 'utf8');
    return JSON.parse(raw);
  }

  const jsonBlob = assertString(args.jsonBlob, 'jsonBlob');
  return JSON.parse(jsonBlob);
}

function normalizeTags(tags: unknown): string[] {
  if (!Array.isArray(tags)) return [];
  return tags
    .map((t) => String(t).trim())
    .filter((t) => t.length > 0)
    .slice(0, 20);
}

function makeTitle(summary: string): string {
  const trimmed = summary.trim();
  if (trimmed.length <= 80) return trimmed;
  return `${trimmed.slice(0, 77)}...`;
}

interface NormalizedAndroidEvent {
  summary: string;
  timestamp: number;
  tags: string[];
  sessionId: string;
}

function normalizeAndroidExport(payload: AndroidExportPayload): NormalizedAndroidEvent[] {
  const rawEvents = Array.isArray(payload.events) ? payload.events : [];
  const deviceId = typeof payload.device_id === 'string' ? payload.device_id : 'android_01';

  const normalized: NormalizedAndroidEvent[] = [];
  for (const ev of rawEvents) {
    const summary = typeof ev?.summary === 'string' ? ev.summary.trim() : '';
    const timestamp = Number(ev?.timestamp);
    if (!summary || !Number.isFinite(timestamp)) continue;

    normalized.push({
      summary,
      timestamp,
      tags: normalizeTags(ev?.tags),
      sessionId: deviceId,
    });
  }

  return normalized;
}

function commitToDatabase(events: NormalizedAndroidEvent[]): IngestResult {
  if (!events || events.length === 0) {
    return { inserted: 0, skipped: 0, total: 0 };
  }

  const db = openHubDb();

  try {
    ensureLearningEventsSchema(db);

    // De-dupe strategy: (timestamp, description) uniqueness.
    const existsStmt = db.prepare(
      'SELECT id FROM learning_events WHERE timestamp = ? AND description = ? LIMIT 1',
    );

    const insertStmt = db.prepare(
      `INSERT INTO learning_events (
        event_type,
        app_source,
        source_file,
        source_function,
        project_id,
        session_id,
        timestamp,
        title,
        description,
        severity,
        applies_to,
        status
      ) VALUES (
        @event_type,
        @app_source,
        @source_file,
        @source_function,
        @project_id,
        @session_id,
        @timestamp,
        @title,
        @description,
        @severity,
        @applies_to,
        @status
      )`,
    );

    let inserted = 0;
    let skipped = 0;

    const tx = db.transaction(() => {
      for (const ev of events) {
        const already = existsStmt.get(ev.timestamp, ev.summary);
        if (already) {
          skipped++;
          continue;
        }

        // NOTE: learning_events.event_type is constrained.
        // We store chat exports as 'insight' and preserve chat semantics in tags/title.
        insertStmt.run({
          event_type: 'insight',
          app_source: 'vibe',
          source_file: null,
          source_function: 'vibe_tutor:ingest-export',
          project_id: 'vibe_tutor',
          session_id: ev.sessionId,
          timestamp: ev.timestamp,
          title: makeTitle(`Chat: ${ev.summary}`),
          description: ev.summary,
          severity: 'info',
          applies_to: JSON.stringify(ev.tags),
          status: 'active',
        });

        inserted++;
      }
    });

    tx();

    return { inserted, skipped, total: events.length };
  } finally {
    try {
      db.close();
    } catch {
      // ignore
    }
  }
}

async function ingestMemories(args: IngestExportArgs): Promise<IngestResult> {
  const payload = await readExportPayload(args);
  const events = normalizeAndroidExport(payload);
  return commitToDatabase(events);
}

function registerIpcHandlers(): void {
  ipcMain.handle('dialog:openFile', async (event) => {
    try {
      assertTrustedIpcSender(event);

      const result = await dialog.showOpenDialog({
        title: 'Import Android Export',
        properties: ['openFile'],
        filters: [{ name: 'JSON Exports', extensions: ['json'] }],
      });

      if (result.canceled || !result.filePaths || result.filePaths.length === 0) {
        return null;
      }

      return result.filePaths[0];
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      throw new Error(`Failed to open file picker: ${message}`);
    }
  });

  ipcMain.handle('ingest-export', async (_event, args: IngestExportArgs) => {
    try {
      assertTrustedIpcSender(_event);

      if (!args || typeof args !== 'object') {
        throw new Error('ingest-export requires args { filePath } or { jsonBlob }');
      }

      const result = await ingestMemories(args);
      console.log(`[ingest] Finished: ${result.inserted} inserted, ${result.skipped} skipped.`);
      return { ok: true, result };
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      return { ok: false, error: message };
    }
  });

  // Electron-store IPC handlers (synchronous)
  const store = new Store() as unknown as {
    get: (key: string) => unknown;
    set: (key: string, value: unknown) => void;
    delete: (key: string) => void;
    clear: () => void;
  };

  ipcMain.on('store:get', (event, key: string) => {
    try {
      assertTrustedIpcSender(event);
      event.returnValue = store.get(key);
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      console.error(`[Store] Failed to get key '${key}':`, message);
      event.returnValue = null;
    }
  });

  ipcMain.on('store:set', (event, key: string, value: unknown) => {
    try {
      assertTrustedIpcSender(event);
      store.set(key, value);
      event.returnValue = undefined;
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      console.error(`[Store] Failed to set key '${key}':`, message);
    }
  });

  ipcMain.on('store:delete', (event, key: string) => {
    try {
      assertTrustedIpcSender(event);
      store.delete(key);
      event.returnValue = undefined;
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      console.error(`[Store] Failed to delete key '${key}':`, message);
    }
  });

  ipcMain.on('store:clear', (event) => {
    try {
      assertTrustedIpcSender(event);
      store.clear();
      event.returnValue = undefined;
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      console.error(`[Store] Failed to clear store:`, message);
    }
  });
}

function createMainWindow(): BrowserWindow {
  const win = new BrowserWindow({
    width: 1200,
    height: 800,
    webPreferences: {
      // Your preload/IPC bridge should live here.
      preload: path.join(__dirname, 'preload.js'),
      contextIsolation: true,
      nodeIntegration: false,
      sandbox: true,
    },
  });

  return win;
}

function registerWebContentsGuards(): void {
  app.on('web-contents-created', (_event, contents) => {
    // Prevent unexpected navigations (common attack vector).
    contents.on('will-navigate', (navEvent, navigationUrl) => {
      if (!isAllowedRendererUrl(navigationUrl)) {
        navEvent.preventDefault();
      }
    });

    // Prevent window.open / new-window popups.
    contents.setWindowOpenHandler(() => ({ action: 'deny' }));
  });
}

async function loadRenderer(win: BrowserWindow): Promise<void> {
  if (isDevMode()) {
    await win.loadURL(DEV_SERVER_URL);
    return;
  }

  await win.loadFile(path.join(__dirname, '../dist/index.html'));
}

app.whenReady().then(() => {
  console.info(`[main] ready (devMode=${String(isDevMode())})`);
  registerWebContentsGuards();
  registerIpcHandlers();

  const win = createMainWindow();

  void loadRenderer(win);
});

app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') {
    app.quit();
  }
});

import { GoogleGenAI } from '@google/genai';
import cors from 'cors';
import crypto from 'crypto';
import dotenv from 'dotenv';
import express from 'express';
import helmet from 'helmet';
import fs from 'node:fs';
import path from 'node:path';

dotenv.config();

const app = express();

// Security headers (relaxed for API-only service)
app.use(helmet({ contentSecurityPolicy: false }));
const PORT = process.env.PORT || 3001;

// ============== CONFIGURATION ==============

// Google Gemini (Primary AI provider)
const GEMINI_CONFIG = {
  model: 'gemini-2.0-flash', // Fast, cheap, great for education
  systemInstruction: `You are Vibe Tutor, a friendly and patient AI learning companion designed for children and young learners. You specialize in making education fun, engaging, and accessible.

Key behaviors:
- Use simple, encouraging language appropriate for children
- Break complex topics into small, digestible steps
- Celebrate effort and progress, not just correct answers
- Use analogies, examples, and gentle humor
- If a child seems frustrated, offer encouragement and a different approach
- Never use sarcasm, condescension, or inappropriate content
- Keep responses concise (2-3 paragraphs max unless explaining a complex topic)
- Use emoji sparingly to keep things fun 🌟`,
};

// OpenRouter (Fallback provider)
const OPENROUTER_CONFIG = {
  baseURL: 'https://openrouter.ai/api/v1',
  model: 'deepseek/deepseek-chat',
  timeout: 30000,
};

// Initialize Gemini client (lazy — only if key is present)
const geminiClient = process.env.GEMINI_API_KEY
  ? new GoogleGenAI({ apiKey: process.env.GEMINI_API_KEY })
  : null;

// Rate limiting
const rateLimit = new Map();
const RATE_LIMIT_WINDOW = 60000; // 1 minute
const MAX_REQUESTS_PER_WINDOW = 30;

// Content filter for child safety
const INAPPROPRIATE_PATTERNS = [
  /\b(violence|violent|kill|death|die|dead|suicide|drug|alcohol|sex|nude|porn)\b/gi,
  /\b(hate|racist|discrimination)\b/gi,
  /\b(damn|hell|shit|fuck|ass|bitch)\b/gi,
];

function filterInappropriateContent(text) {
  for (const pattern of INAPPROPRIATE_PATTERNS) {
    if (pattern.test(text)) {
      return { safe: false, reason: 'Content contains inappropriate material' };
    }
  }
  return { safe: true };
}

// ============== MIDDLEWARE ==============

// CORS: Allow Capacitor app, localhost dev, and any custom origins via env
const extraOrigins = process.env.ALLOWED_ORIGINS ? process.env.ALLOWED_ORIGINS.split(',') : [];

app.use(
  cors({
    origin: function (origin, callback) {
      const allowedOrigins = [
        'http://localhost:5173',
        'http://localhost:5174',
        'http://localhost:5175',
        'http://localhost:3000',
        'http://127.0.0.1:5173',
        'capacitor://localhost',
        'ionic://localhost',
        'http://localhost',
        ...extraOrigins,
      ];

      // No origin = same-origin, Capacitor native HTTP, or server-to-server
      if (!origin) return callback(null, true);
      if (allowedOrigins.includes(origin)) return callback(null, true);

      // Allow any capacitor/ionic origin
      if (origin.startsWith('capacitor://') || origin.startsWith('ionic://')) {
        return callback(null, true);
      }

      return callback(new Error('Not allowed by CORS'));
    },
    credentials: true,
  }),
);

app.use(express.json());

// ============== ANALYTICS LOGGING ==============

// Optional: save lightweight analytics events for debugging.
// In managed hosts (Render), this writes to ephemeral disk by default.
app.post('/api/analytics/log', validateSession, (req, res) => {
  try {
    const { event, data } = req.body || {};

    const logDir = process.env.ANALYTICS_LOG_DIR || path.join(process.cwd(), 'logs');
    if (!fs.existsSync(logDir)) {
      fs.mkdirSync(logDir, { recursive: true });
    }

    const logFile = path.join(logDir, `analytics-${new Date().toISOString().split('T')[0]}.log`);
    const logEntry = `${JSON.stringify({
      timestamp: new Date().toISOString(),
      session: req.headers.authorization?.replace('Bearer ', '').substring(0, 8),
      event,
      data,
    })}\n`;

    fs.appendFileSync(logFile, logEntry);
    res.json({ status: 'success' });
  } catch (error) {
    console.error('[Analytics] Logging failed:', error);
    // Never break the app flow for analytics.
    res.json({ status: 'ignored' });
  }
});

// Rate limiting middleware
app.use((req, res, next) => {
  const clientId = req.ip;
  const now = Date.now();

  if (!rateLimit.has(clientId)) {
    rateLimit.set(clientId, { count: 1, resetTime: now + RATE_LIMIT_WINDOW });
    next();
    return;
  }

  const limit = rateLimit.get(clientId);

  if (now > limit.resetTime) {
    limit.count = 1;
    limit.resetTime = now + RATE_LIMIT_WINDOW;
    rateLimit.set(clientId, limit);
    next();
    return;
  }

  if (limit.count >= MAX_REQUESTS_PER_WINDOW) {
    res.status(429).json({
      error: 'Too many requests. Please try again later.',
      retryAfter: Math.ceil((limit.resetTime - now) / 1000),
    });
    return;
  }

  limit.count++;
  rateLimit.set(clientId, limit);
  next();
});

// ============== SESSION MANAGEMENT ==============

const sessions = new Map();
const SESSION_DURATION = 30 * 60 * 1000; // 30 minutes

// Rate limiting for session initialization (prevent DoS/enumeration attacks)
const sessionInitRateLimit = new Map();
const SESSION_INIT_LIMIT = 50; // Max 50 sessions per IP per hour (was 5 — too restrictive for dev/retries)
const SESSION_INIT_WINDOW = 60 * 60 * 1000; // 1 hour

function generateSessionToken() {
  return crypto.randomBytes(32).toString('hex');
}

// Initialize session endpoint (with rate limiting)
app.post('/api/session/init', (req, res) => {
  const clientIp = req.ip;
  const now = Date.now();

  // Check session creation rate limit
  if (sessionInitRateLimit.has(clientIp)) {
    const limit = sessionInitRateLimit.get(clientIp);
    if (now < limit.resetTime) {
      if (limit.count >= SESSION_INIT_LIMIT) {
        res.status(429).json({
          error: 'Too many session requests. Please try again later.',
          retryAfter: Math.ceil((limit.resetTime - now) / 1000),
        });
        return;
      }
      limit.count++;
    } else {
      limit.count = 1;
      limit.resetTime = now + SESSION_INIT_WINDOW;
    }
    sessionInitRateLimit.set(clientIp, limit);
  } else {
    sessionInitRateLimit.set(clientIp, { count: 1, resetTime: now + SESSION_INIT_WINDOW });
  }

  const token = generateSessionToken();
  const sessionData = {
    createdAt: Date.now(),
    requestCount: 0,
    dailyUsage: 0,
  };

  sessions.set(token, sessionData);

  // Clean old sessions
  for (const [key, value] of sessions.entries()) {
    if (Date.now() - value.createdAt > SESSION_DURATION) {
      sessions.delete(key);
    }
  }

  res.json({
    token,
    expiresIn: SESSION_DURATION / 1000,
  });
});

// Validate session middleware
function validateSession(req, res, next) {
  const token = req.headers.authorization?.replace('Bearer ', '');

  if (!token || !sessions.has(token)) {
    res.status(401).json({ error: 'Invalid or expired session' });
    return;
  }

  const session = sessions.get(token);

  if (Date.now() - session.createdAt > SESSION_DURATION) {
    sessions.delete(token);
    res.status(401).json({ error: 'Session expired' });
    return;
  }

  session.requestCount++;

  // Daily usage limit (150 requests per day)
  const dayStart = new Date().setHours(0, 0, 0, 0);
  if (session.createdAt >= dayStart) {
    session.dailyUsage++;
    if (session.dailyUsage > 150) {
      res.status(429).json({
        error: 'Daily usage limit reached. Please try again tomorrow.',
      });
      return;
    }
  } else {
    session.dailyUsage = 1;
  }

  req.session = session; // eslint-disable-line no-param-reassign
  next();
}

// ============== GEMINI API (Primary) ==============

/** Convert OpenAI-style messages to Gemini format */
function toGeminiContents(messages) {
  return messages
    .filter((m) => m.role !== 'system') // system handled via systemInstruction
    .map((m) => ({
      role: m.role === 'assistant' ? 'model' : 'user',
      parts: [{ text: m.content }],
    }));
}

async function callGemini(messages) {
  if (!geminiClient) throw new Error('GEMINI_API_KEY not configured');

  // Extract client-sent system prompt (from AI_TUTOR_PROMPT / AI_FRIEND_PROMPT)
  // and use it as Gemini's systemInstruction. Fall back to server default.
  const clientSystemMsg = messages.find((m) => m.role === 'system');
  const systemInstruction = clientSystemMsg?.content || GEMINI_CONFIG.systemInstruction;

  console.log('[Gemini] System prompt source:', clientSystemMsg ? 'CLIENT' : 'SERVER-DEFAULT');
  console.log('[Gemini] System prompt preview:', `${systemInstruction.slice(0, 80)}...`);

  const contents = toGeminiContents(messages);

  const response = await geminiClient.models.generateContent({
    model: GEMINI_CONFIG.model,
    contents,
    config: {
      systemInstruction,
      maxOutputTokens: 2000,
      temperature: 0.7,
      topP: 0.95,
      // Explicitly disable Google Search grounding to prevent external citations
      tools: [],
      safetySettings: [
        { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_LOW_AND_ABOVE' },
        { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_LOW_AND_ABOVE' },
        { category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold: 'BLOCK_LOW_AND_ABOVE' },
        { category: 'HARM_CATEGORY_DANGEROUS_CONTENT', threshold: 'BLOCK_LOW_AND_ABOVE' },
      ],
    },
  });

  const text = response.text ?? '';
  return text;
}

// ============== OPENROUTER API (Fallback) ==============

async function callOpenRouter(messages) {
  const apiKey = process.env.OPENROUTER_API_KEY;
  if (!apiKey) throw new Error('OPENROUTER_API_KEY not configured');

  const response = await fetch(`${OPENROUTER_CONFIG.baseURL}/chat/completions`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${apiKey}`,
      'HTTP-Referer': 'https://vibe-tutor.app',
      'X-Title': 'Vibe Tutor',
    },
    body: JSON.stringify({
      model: OPENROUTER_CONFIG.model,
      messages,
      temperature: 0.7,
      max_tokens: 2000,
    }),
  });

  if (!response.ok) {
    const errorText = await response.text();
    console.error(`[OpenRouter] Error ${response.status}:`, errorText);
    throw new Error(`OpenRouter API error: ${response.status}`);
  }

  const data = await response.json();
  return data.choices?.[0]?.message?.content ?? '';
}

// ============== UNIFIED CHAT ENDPOINT ==============

/** Try Gemini first, fallback to OpenRouter */
async function getAIResponse(messages) {
  // Try Gemini (primary)
  if (geminiClient) {
    try {
      return { text: await callGemini(messages), provider: 'gemini' };
    } catch (err) {
      console.warn('[AI] Gemini failed, trying fallback:', err.message);
    }
  }

  // Try OpenRouter (fallback)
  if (process.env.OPENROUTER_API_KEY) {
    try {
      return { text: await callOpenRouter(messages), provider: 'openrouter' };
    } catch (err) {
      console.error('[AI] OpenRouter fallback failed:', err.message);
    }
  }

  throw new Error('No AI provider available');
}

// Primary chat endpoint — used by both /api/chat and /api/openrouter/chat
app.post(['/api/chat', '/api/openrouter/chat'], validateSession, async (req, res) => {
  try {
    const { messages } = req.body;

    if (!messages || !Array.isArray(messages)) {
      res.status(400).json({ error: 'Invalid request format' });
      return;
    }

    // Content safety check on user input
    const lastMessage = messages[messages.length - 1];
    if (lastMessage?.role === 'user') {
      const check = filterInappropriateContent(lastMessage.content);
      if (!check.safe) {
        res.status(400).json({ error: 'Request blocked', reason: check.reason });
        return;
      }
    }

    const { text, provider } = await getAIResponse(messages);

    // Filter AI response
    const responseCheck = filterInappropriateContent(text);
    const safeText = responseCheck.safe
      ? text
      : "I cannot provide that information. Let's focus on your learning instead!";

    // Return in OpenAI-compatible format for frontend compatibility
    res.json({
      choices: [{ message: { role: 'assistant', content: safeText } }],
      message: safeText,
      provider,
    });
  } catch (error) {
    console.error('[Chat] Error:', error.message);
    res.status(500).json({ error: 'Service error', message: 'Please try again later' });
  }
});

