  'listen.moe',
  'ice.somafm.com',
  'ice1.somafm.com',
  'ice2.somafm.com',
  'ice3.somafm.com',
  'ice4.somafm.com',
  'ice6.somafm.com',
  'fm997.wqxr.org',
  'stream.wqxr.org',
  'liveradio.swr.de',
  'stream.srg-ssr.ch',
  'streams.kqed.org',
  'playerservices.streamtheworld.com',
  'stream.radioparadise.com',
  'audio-edge-es6pf.fra.h.radiomast.io',
  'streams.fluxfm.de',
  'stream.laut.fm',
  // Jamendo music API + audio CDN
  'api.jamendo.com',
  'mp3d.jamendo.com',
  'mp3l.jamendo.com',
  // AnimeNfo Radio
  'radionomy.com',
  'streamow6.radionomy.com',
];

app.get('/api/radio/stream', async (req, res) => {
  const streamUrl = req.query.url;

  if (!streamUrl || typeof streamUrl !== 'string') {
    res.status(400).json({ error: 'Missing `url` query parameter' });
    return;
  }

  let parsed;
  try {
    parsed = new URL(streamUrl);
  } catch {
    res.status(400).json({ error: 'Invalid URL' });
    return;
  }

  // Security: only proxy known radio domains
  const isDomainAllowed = ALLOWED_RADIO_DOMAINS.some(
    (d) => parsed.hostname === d || parsed.hostname.endsWith(`.${d}`),
  );

  if (!isDomainAllowed) {
    res.status(403).json({ error: 'Domain not allowed', hostname: parsed.hostname });
    return;
  }

  try {
    const upstream = await fetch(streamUrl, {
      headers: {
        'User-Agent': 'VibeTutor/1.0',
        Accept: 'audio/*,*/*',
      },
      signal: AbortSignal.timeout(10000),
    });

    if (!upstream.ok) {
