function getClientId(): string {
  if (typeof window !== 'undefined' && window.__JAMENDO_CLIENT_ID__) {
    return window.__JAMENDO_CLIENT_ID__;
  }
  return '';
}

/** Track an API call for rate-limit awareness. */
function trackApiCall(): void {
  try {
    const now = new Date();
    const monthKey = `${now.getFullYear()}-${now.getMonth()}`;

    const raw = localStorage.getItem(USAGE_KEY);
    const data: { month: string; count: number } = raw
      ? (JSON.parse(raw) as { month: string; count: number })
      : { month: monthKey, count: 0 };

    if (data.month !== monthKey) {
      data.month = monthKey;
      data.count = 0;
    }
    data.count += 1;

    localStorage.setItem(USAGE_KEY, JSON.stringify(data));
  } catch {
    // localStorage may be unavailable — silently ignore
  }
}

/** Get current usage stats. */
export function getUsageStats(): {
  requestsThisMonth: number;
  monthlyLimit: number;
  remaining: number;
} {
  try {
    const now = new Date();
    const monthKey = `${now.getFullYear()}-${now.getMonth()}`;

    const raw = localStorage.getItem(USAGE_KEY);
    const data: { month: string; count: number } = raw
      ? (JSON.parse(raw) as { month: string; count: number })
      : { month: monthKey, count: 0 };

    if (data.month !== monthKey) {
      return { requestsThisMonth: 0, monthlyLimit: MONTHLY_LIMIT, remaining: MONTHLY_LIMIT };
    }
    return {
      requestsThisMonth: data.count,
      monthlyLimit: MONTHLY_LIMIT,
      remaining: Math.max(0, MONTHLY_LIMIT - data.count),
    };
  } catch {
    return { requestsThisMonth: 0, monthlyLimit: MONTHLY_LIMIT, remaining: MONTHLY_LIMIT };
  }
}

// ---------------------------------------------------------------------------
// API methods
// ---------------------------------------------------------------------------

interface JamendoApiResponse {
  headers: { status: string; code: number; results_count: number };
  results: JamendoTrack[];
}

async function jamendoFetch(params: Record<string, string>): Promise<JamendoTrack[]> {
  const clientId = getClientId();
  if (!clientId) {
    console.warn('[Jamendo] No client ID configured — set window.__JAMENDO_CLIENT_ID__');
    return [];
  }

  const url = new URL(`${JAMENDO_API_BASE}/tracks/`);
  url.searchParams.set('client_id', clientId);
  url.searchParams.set('format', 'json');
  url.searchParams.set('audioformat', 'mp32'); // Good quality VBR MP3
  url.searchParams.set('imagesize', '200'); // Reasonable album art size
  url.searchParams.set('include', 'musicinfo+licenses');

  for (const [key, value] of Object.entries(params)) {
    url.searchParams.set(key, value);
  }

  trackApiCall();

  const res = await fetch(url.toString());
  if (!res.ok) {
    throw new Error(`Jamendo API error: ${res.status}`);
  }

  const json: JamendoApiResponse = await res.json();
  if (json.headers.code !== 0) {
    throw new Error(`Jamendo API error: ${json.headers.status}`);
  }

  return json.results;
}

/**
 * Search tracks by free-text query.
 * Applies smart-search mapping when query matches a known keyword.
 */
export async function searchTracks(params: JamendoSearchParams): Promise<JamendoTrack[]> {
  const fetchParams: Record<string, string> = {};

  // Smart search: map common keywords to genre tags
  if (params.query) {
    const lower = params.query.toLowerCase().trim();
    const genreKey = SMART_SEARCH_MAP[lower];
    if (genreKey && JAMENDO_GENRES[genreKey]) {
      fetchParams.tags = JAMENDO_GENRES[genreKey].tags;
    } else {
      fetchParams.search = params.query;
    }
  }

  if (params.tags) fetchParams.tags = params.tags;
  if (params.limit) fetchParams.limit = String(params.limit);
  if (params.offset) fetchParams.offset = String(params.offset);
  if (params.order) fetchParams.order = params.order;

  fetchParams.limit = fetchParams.limit ?? '20';

  return jamendoFetch(fetchParams);
}

/** Browse tracks by genre key (e.g. 'anime', 'edm'). */
export async function browseByGenre(
  genre: string,
  limit = 20,
  offset = 0,
): Promise<JamendoTrack[]> {
  const mapping = JAMENDO_GENRES[genre];
  if (!mapping) {
    console.warn(`[Jamendo] Unknown genre: ${genre}`);
    return [];
  }

  return jamendoFetch({
    tags: mapping.tags,
    limit: String(limit),
    offset: String(offset),
    order: 'popularity_total',
  });
}

/** Fetch currently trending tracks. */
export async function getTrending(limit = 20): Promise<JamendoTrack[]> {
  return jamendoFetch({
    order: 'popularity_week',
    limit: String(limit),
  });
}

