// Playback helpers
// ---------------------------------------------------------------------------

/**
 * Get the playable stream URL for a Jamendo track.
 * On Android, routes through the backend proxy to bypass WebView CSP.
 */
export function getStreamUrl(track: JamendoTrack): string {
  const rawUrl = track.audio;
  if (!rawUrl) return '';

  // Android needs proxy to bypass WebView CSP
  if (Capacitor.getPlatform() === 'android') {
    const apiBase = API_CONFIG.baseURL;
    return `${apiBase}/api/radio/stream?url=${encodeURIComponent(rawUrl)}`;
  }

  return rawUrl;
}

/** Format seconds to mm:ss display. */
export function formatDuration(seconds: number): string {
  const m = Math.floor(seconds / 60);
  const s = Math.floor(seconds % 60);
  return `${m}:${s.toString().padStart(2, '0')}`;
}

